/**
 * @name Taint flow from HTTP request path to ClassLoader resource loading
 * @description Request URI components flow to ClassLoader.getResource/getResourceAsStream without path traversal validation
 * @kind path-problem
 * @problem.severity error
 * @id java/myfaces-request-to-classloader-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ClassLoaderResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Request URI / path components from servlet request
    exists(MethodCall mc |
      mc.getMethod().hasName(["getRequestURI", "getPathInfo", "getServletPath", "getRequestURL", "getParameter", "getHeader"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest")
      ) and
      source.asExpr() = mc
    )
    or
    // Also consider ExternalContext resource name methods as potential sources if they derive from request
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResourceName", "getLibraryName"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.myfaces.shared.resource", "ResourceMeta") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ExternalContext.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.faces.context", "ExternalContext") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClassLoaderResourceFlow = TaintTracking::Global<ClassLoaderResourceConfig>;
import ClassLoaderResourceFlow::PathGraph

from ClassLoaderResourceFlow::PathNode source, ClassLoaderResourceFlow::PathNode sink
where ClassLoaderResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP request data flows to resource loading at $@.", sink.getNode(), "resource load"
